import{_ as i,c as a,o as e,aj as n}from"./chunks/framework.VtnL2jmu.js";const c=JSON.parse('{"title":"自部署vscode网页版","description":"","frontmatter":{},"headers":[],"relativePath":"Linux/自部署vscode网页版.md","filePath":"Linux/自部署vscode网页版.md"}'),h={name:"Linux/自部署vscode网页版.md"};function l(t,s,p,k,r,d){return e(),a("div",null,[...s[0]||(s[0]=[n(`<h1 id="自部署vscode网页版" tabindex="-1">自部署vscode网页版 <a class="header-anchor" href="#自部署vscode网页版" aria-label="Permalink to “自部署vscode网页版”">​</a></h1><h2 id="🚀-用脚本一键安装-code-server" tabindex="-1">🚀 用脚本一键安装 code-server <a class="header-anchor" href="#🚀-用脚本一键安装-code-server" aria-label="Permalink to “🚀 用脚本一键安装 code-server”">​</a></h2><p>在 WSL 终端执行：</p><div class="language-bash"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">curl</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -fsSL</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> https://code-server.dev/install.sh</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;"> |</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;"> sh</span></span></code></pre></div><h2 id="⚙️-启动并设置" tabindex="-1">⚙️ 启动并设置 <a class="header-anchor" href="#⚙️-启动并设置" aria-label="Permalink to “⚙️ 启动并设置”">​</a></h2><p><strong>1. 先创建配置文件设置密码</strong></p><div class="language-bash"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">mkdir</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -p</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> ~/.config/code-server</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">cat</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;"> &gt;</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> ~/.config/code-server/config.yaml</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;"> &lt;&lt;</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> EOF</span></span>
<span class="line"><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">bind-addr: 0.0.0.0:8080</span></span>
<span class="line"><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">auth: password</span></span>
<span class="line"><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">password: 你的密码</span></span>
<span class="line"><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">cert: false</span></span>
<span class="line"><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">EOF</span></span></code></pre></div><p><strong>2. 启动服务</strong></p><div class="language-bash"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">code-server</span></span></code></pre></div><p>看到类似 <code>HTTP server listening on http://0.0.0.0:8080</code> 的输出就成功了。</p><h2 id="🌐-从-windows-访问" tabindex="-1">🌐 从 Windows 访问 <a class="header-anchor" href="#🌐-从-windows-访问" aria-label="Permalink to “🌐 从 Windows 访问”">​</a></h2><p>打开 Windows 上的浏览器（Chrome/Edge），访问：</p><div class="language-"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span>http://localhost:8080</span></span></code></pre></div><p>输入你刚才设置的密码，就能用上和 VS Code 一模一样的网页编辑界面了。</p><h2 id="💡-让它在后台一直运行" tabindex="-1">💡 让它在后台一直运行 <a class="header-anchor" href="#💡-让它在后台一直运行" aria-label="Permalink to “💡 让它在后台一直运行”">​</a></h2><p>如果关掉 WSL 窗口也想让它继续跑，可以用 systemd 或简单点的 <code>nohup</code>：</p><div class="language-bash"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"># 后台运行并记录日志</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">nohup</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> code-server</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> --bind-addr</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> 0.0.0.0:8080</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> --auth</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> password</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> --password</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> 你的密码</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;"> &gt;</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> ~/code-server.log</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;"> 2&gt;&amp;1</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> &amp;</span></span>
<span class="line"></span>
<span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"># 查看运行状态</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">ps</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> aux</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;"> |</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;"> grep</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> code-server</span></span>
<span class="line"></span>
<span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"># 需要停止时</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">pkill</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> code-server</span></span></code></pre></div><h2 id="🛠️-常见小问题" tabindex="-1">🛠️ 常见小问题 <a class="header-anchor" href="#🛠️-常见小问题" aria-label="Permalink to “🛠️ 常见小问题”">​</a></h2><ul><li><strong>端口被占</strong>：换个端口，比如 <code>--bind-addr 0.0.0.0:8888</code></li><li><strong>想用 HTTPS</strong>：WSL 本地开发一般不需要，用 HTTP 即可</li><li><strong>WSL 里面打不开浏览器</strong>：正常的，网页端是跑在 WSL 里、用 Windows 浏览器看</li></ul>`,19)])])}const g=i(h,[["render",l]]);export{c as __pageData,g as default};
